// Handbook display colophons — one symbolic ref per RBZ_* zipper constant.
// Onboarding group (8)
pub const RBTDRM_COLOPHON_ONBOARD_START_HERE: &str = "rbw-o";
pub const RBTDRM_COLOPHON_ONBOARD_CRASH_COURSE: &str = "rbw-Occ";
